# Allowlist of trusted configuration sources
ALLOWED_CONFIG_HOSTS = [
    "raw.githubusercontent.com",
    "api.github.com",
]

# Allowlist of allowed package name patterns (alphanumeric, hyphens, underscores)
PACKAGE_NAME_PATTERN = re.compile(r'^[a-zA-Z0-9][a-zA-Z0-9._-]*[a-zA-Z0-9]$|^[a-zA-Z0-9]$')

# Maximum allowed config file size (to prevent DoS)
MAX_CONFIG_SIZE = 1024 * 100  # 100KB

# Expected SHA256 hash of the config file (set this to your known good hash)
# In production, replace with actual hash of your config file
EXPECTED_CONFIG_HASH = os.environ.get("DEPS_CONFIG_HASH", None)

